interface Pope {
  name: string;
  startYear: string;
  endYear: string;
  isAntiPope?: boolean;
  description?: string;
}

export const popes: Pope[] = [
  // Early Popes (1st-3rd century)
  { name: "St. Peter", startYear: "0030", endYear: "0064", description: "Birth name: Simon bar Jonah. The first Bishop of Rome and chief of the Apostles, regarded as the foundation of the Catholic Church. Traditionally martyred by crucifixion under Emperor Nero in Rome." },
  { name: "St. Linus", startYear: "0067", endYear: "0076", description: "Birth name: Linus. The second Bishop of Rome, mentioned by Paul in 2 Timothy 4:21. Little is known of his pontificate, but he is traditionally credited with ordaining clergy and is venerated as a martyr." },
  { name: "St. Anacletus", startYear: "0076", endYear: "0088", description: "Birth name: Anacletus (also called Cletus). One of the earliest successors of Peter, he is said to have organized the Roman clergy and built a memorial over Peter's tomb." },
  { name: "St. Clement I", startYear: "0088", endYear: "0099", description: "Birth name: Clement. Author of the First Epistle of Clement, one of the oldest surviving Christian documents outside the New Testament, written to resolve disputes in the Corinthian church." },
  { name: "St. Evaristus", startYear: "0099", endYear: "0107", description: "Birth name: Evaristus. Traditionally said to have been of Greek or Jewish origin and to have divided Rome into parishes." },
  { name: "St. Alexander I", startYear: "0107", endYear: "0115", description: "Birth name: Alexander. Traditionally credited with introducing holy water mixed with salt for the purification of Christian homes." },
  { name: "St. Sixtus I", startYear: "0115", endYear: "0125", description: "Birth name: Sixtus (or Xystus). Credited with several liturgical regulations, including the rule that only ministers could touch holy vessels." },
  { name: "St. Telesphorus", startYear: "0125", endYear: "0136", description: "Birth name: Telesphorus. The only second-century pope whose martyrdom is historically attested, confirmed by Irenaeus of Lyon." },
  { name: "St. Hyginus", startYear: "0136", endYear: "0140", description: "Birth name: Hyginus. He reigned during the height of Gnostic influence in Rome, confronting teachers such as Valentinus and Cerdon." },
  { name: "St. Pius I", startYear: "0140", endYear: "0155", description: "Birth name: Pius. Brother of Hermas, the author of The Shepherd, he led the Roman church during a period of significant theological ferment." },
  { name: "St. Anicetus", startYear: "0155", endYear: "0166", description: "Birth name: Anicetus. Notable for his meeting with Polycarp of Smyrna to discuss the Quartodeciman controversy over the date of Easter." },
  { name: "St. Soter", startYear: "0166", endYear: "0175", description: "Birth name: Soter. Praised by Bishop Dionysius of Corinth for his generosity in sending aid to other churches." },
  { name: "St. Eleutherius", startYear: "0175", endYear: "0189", description: "Birth name: Eleutherius. He reportedly received missionaries from Britain and is associated with early Christian mission to that island." },
  { name: "St. Victor I", startYear: "0189", endYear: "0199", description: "Birth name: Victor. The first pope known to have been of African origin, he forcefully asserted Roman authority by threatening to excommunicate Eastern churches over the Easter date controversy." },
  { name: "St. Zephyrinus", startYear: "0199", endYear: "0217", description: "Birth name: Zephyrinus. His long pontificate was troubled by fierce theological controversies over the nature of Christ, including disputes with Hippolytus." },
  { name: "St. Callixtus I", startYear: "0217", endYear: "0222", description: "Birth name: Callixtus (Callistus). A former slave who rose to become pope, he developed the Catacomb of Callixtus and adopted a notably lenient policy toward Christians who had lapsed." },
  { name: "Hippolytus", startYear: "0217", endYear: "0235", isAntiPope: true, description: "Birth name: Hippolytus. A prolific theologian who set himself up as a rival bishop in opposition to Popes Callixtus I, Urban I, and Pontian, making him the first known antipope. He was eventually exiled to Sardinia, where he reconciled with Pope Pontian." },
  { name: "St. Urban I", startYear: "0222", endYear: "0230", description: "Birth name: Urban. He led the Roman church during a relatively peaceful period under Emperor Alexander Severus." },
  { name: "St. Pontian", startYear: "0230", endYear: "0235", description: "Birth name: Pontian. He became the first pope to abdicate, resigning after being exiled to the Sardinian mines by Emperor Maximinus Thrax." },
  { name: "St. Anterus", startYear: "0235", endYear: "0236", description: "Birth name: Anterus. He reigned for only about six weeks, one of the shortest pontificates in history. He is traditionally credited with collecting the acts of the martyrs." },
  { name: "St. Fabian", startYear: "0236", endYear: "0250", description: "Birth name: Fabian. His election was reportedly prompted by a dove landing on his head, seen as a divine sign. He reorganized the Roman church into seven diaconal districts and was martyred under the Decian persecution." },
  { name: "St. Cornelius", startYear: "0251", endYear: "0253", description: "Birth name: Cornelius. He faced the rival claim of the antipope Novatian and took a moderate stance in favor of reconciling lapsed Christians." },
  { name: "Novatian", startYear: "0251", endYear: "0258", isAntiPope: true, description: "Birth name: Novatian. A rigorous theologian set up as a rival to Pope Cornelius by followers who opposed any reconciliation of Christians who had lapsed during persecution." },
  { name: "St. Lucius I", startYear: "0253", endYear: "0254", description: "Birth name: Lucius. His pontificate lasted less than a year. Like his predecessor Cornelius, he supported a merciful approach to reconciling lapsed Christians." },
  { name: "St. Stephen I", startYear: "0254", endYear: "0257", description: "Birth name: Stephen. He engaged in a significant controversy with Cyprian of Carthage over whether baptisms performed by heretics were valid, insisting on their validity." },
  { name: "St. Sixtus II", startYear: "0257", endYear: "0258", description: "Birth name: Sixtus (Xystus). He worked to heal the rift over the rebaptism controversy. He was martyred during the persecution of Emperor Valerian, seized and beheaded while teaching." },
  { name: "St. Dionysius", startYear: "0259", endYear: "0268", description: "Birth name: Dionysius. Elected after a three-year vacancy, he reorganized the Roman church and intervened in the theological controversy surrounding the Trinity." },
  { name: "St. Felix I", startYear: "0269", endYear: "0274", description: "Birth name: Felix. His pontificate coincided with the condemnation of Paul of Samosata for adoptionist heresy at the Council of Antioch." },
  { name: "St. Eutychian", startYear: "0275", endYear: "0283", description: "Birth name: Eutychian. Almost nothing is historically certain about his pontificate beyond the bare dates of his reign." },
  { name: "St. Caius", startYear: "0283", endYear: "0296", description: "Birth name: Caius. Tradition holds that he was a relative of Emperor Diocletian and that he decreed the episcopate must be received through the various orders of clergy." },
  { name: "St. Marcellinus", startYear: "0296", endYear: "0304", description: "Birth name: Marcellinus. His pontificate was overshadowed by the Great Persecution of Diocletian, and he was controversially accused of having handed over scriptures under duress." },
  { name: "St. Marcellus I", startYear: "0308", endYear: "0309", description: "Birth name: Marcellus. His brief papacy was consumed by bitter disputes over how to treat Christians who had lapsed during the persecution." },
  { name: "St. Eusebius", startYear: "0309", endYear: "0310", description: "Birth name: Eusebius. His very short pontificate continued the divisive controversy over the reconciliation of lapsed Christians." },
  { name: "St. Miltiades", startYear: "0311", endYear: "0314", description: "Birth name: Miltiades (also Melchiades). He became pope just as Constantine's Edict of Milan granted Christians freedom of worship. He presided over the Lateran Council of 313, the first papal council." },
  // 4th-5th century
  { name: "St. Sylvester I", startYear: "0314", endYear: "0335", description: "Birth name: Sylvester. He served as pope during the reign of Emperor Constantine I and presided over the First Council of Nicaea (325), which condemned Arianism." },
  { name: "St. Marcus", startYear: "0336", endYear: "0336", description: "Birth name: Marcus. He served one of the shortest pontificates on record, reigning for less than nine months." },
  { name: "St. Julius I", startYear: "0337", endYear: "0352", description: "Birth name: Julius. He was a staunch defender of Nicene orthodoxy and a champion of St. Athanasius against the Arians." },
  { name: "Liberius", startYear: "0352", endYear: "0366", description: "Birth name: Liberius. The first pope not to be venerated as a saint, largely because he signed an Arian-leaning creed under pressure from Emperor Constantius II during his exile." },
  { name: "Felix II", startYear: "0355", endYear: "0365", isAntiPope: true, description: "Birth name: Felix. Installed by Emperor Constantius II while the legitimate pope Liberius was still alive and in exile." },
  { name: "St. Damasus I", startYear: "0366", endYear: "0384", description: "Birth name: Damasus. He commissioned St. Jerome to produce the Latin Vulgate Bible and worked to establish Rome's primacy over the universal Church." },
  { name: "Ursicinus", startYear: "0366", endYear: "0367", isAntiPope: true, description: "Birth name: Ursinus. Elected by a rival faction at the same time as the legitimate pope Damasus I, his followers clashed violently with supporters of Damasus." },
  { name: "St. Siricius", startYear: "0384", endYear: "0399", description: "Birth name: Siricius. He issued the earliest surviving papal decretal, formally establishing the practice of binding doctrinal letters from Rome." },
  { name: "St. Anastasius I", startYear: "0399", endYear: "0401", description: "Birth name: Anastasius. He condemned the writings of Origen and was praised by contemporaries such as St. Jerome and St. Augustine for his holiness." },
  { name: "St. Innocent I", startYear: "0401", endYear: "0417", description: "Birth name: Innocent. One of the most assertive early popes in claiming supreme authority, insisting that all major disputes be referred to Rome. His tenure witnessed the sack of Rome by Alaric in 410." },
  { name: "St. Zosimus", startYear: "0417", endYear: "0418", description: "Birth name: Zosimus. He briefly reversed Rome's condemnation of Pelagianism before ultimately upholding it." },
  { name: "St. Boniface I", startYear: "0418", endYear: "0422", description: "Birth name: Boniface. His election was contested by the antipope Eulalius, leading to a schism resolved by Emperor Honorius in his favor." },
  { name: "Eulalius", startYear: "0418", endYear: "0419", isAntiPope: true, description: "Birth name: Eulalius. Elected by a rival faction on the same day as the legitimate pope Boniface I, he was ultimately expelled from Rome by Emperor Honorius." },
  { name: "St. Celestine I", startYear: "0422", endYear: "0432", description: "Birth name: Celestine. He presided over the Council of Ephesus (431), which defined Mary as Theotokos (Mother of God) and condemned Nestorianism." },
  { name: "St. Sixtus III", startYear: "0432", endYear: "0440", description: "Birth name: Sixtus. He built the magnificent mosaics of Santa Maria Maggiore commemorating the Council of Ephesus." },
  { name: "St. Leo I (the Great)", startYear: "0440", endYear: "0461", description: "Birth name: Leo. One of only two popes granted the title 'the Great,' he defined orthodox Christology at the Council of Chalcedon (451). He famously persuaded Attila the Hun to turn back from Rome in 452." },
  { name: "St. Hilarius", startYear: "0461", endYear: "0468", description: "Birth name: Hilarius. He vigorously defended the decrees of the Council of Chalcedon against imperial attempts to compromise on Christology." },
  { name: "St. Simplicius", startYear: "0468", endYear: "0483", description: "Birth name: Simplicius. He oversaw the Church during the fall of the Western Roman Empire in 476, working to maintain orthodoxy amid political collapse." },
  { name: "St. Felix III", startYear: "0483", endYear: "0492", description: "Birth name: Felix. He excommunicated Patriarch Acacius of Constantinople, initiating the Acacian Schism that lasted until 519." },
  { name: "St. Gelasius I", startYear: "0492", endYear: "0496", description: "Birth name: Gelasius. He articulated the influential 'two powers' doctrine, distinguishing between the spiritual authority of the pope and the temporal power of the emperor." },
  { name: "Anastasius II", startYear: "0496", endYear: "0498", description: "Birth name: Anastasius. He attempted to reconcile with Constantinople and end the Acacian Schism, a policy that earned him criticism from rigorists." },
  { name: "St. Symmachus", startYear: "0498", endYear: "0514", description: "Birth name: Symmachus. His election was contested by the antipope Laurentius. A synod established the precedent that the pope cannot be judged by any earthly tribunal." },
  { name: "Laurentius", startYear: "0498", endYear: "0505", isAntiPope: true, description: "Birth name: Laurentius. Elected simultaneously with the legitimate pope Symmachus by a rival faction backed by powerful Roman senators." },
  { name: "St. Hormisdas", startYear: "0514", endYear: "0523", description: "Birth name: Hormisdas. He successfully ended the Acacian Schism in 519 with the Formula of Hormisdas, reaffirming Roman primacy. He is the father of Pope St. Silverius." },
  { name: "St. John I", startYear: "0523", endYear: "0526", description: "Birth name: John. The first pope to visit Constantinople, he traveled on a diplomatic mission for King Theodoric the Great. He died in captivity after Theodoric suspected his loyalty." },
  { name: "St. Felix IV", startYear: "0526", endYear: "0530", description: "Birth name: Felix. Effectively appointed by the Ostrogothic King Theodoric the Great, marking significant royal influence over the papacy." },
  { name: "Boniface II", startYear: "0530", endYear: "0532", description: "Birth name: Boniface. The first Germanic pope, he faced a disputed succession with the antipope Dioscorus." },
  { name: "Dioscorus", startYear: "0530", endYear: "0530", isAntiPope: true, description: "Birth name: Dioscorus. Elected by a rival faction at the same time as Boniface II, his claim became moot when he died just 22 days after his election." },
  { name: "John II", startYear: "0533", endYear: "0535", description: "Birth name: Mercurius. He was the first pope to change his name upon election, taking the name John because his birth name was that of a pagan god." },
  { name: "St. Agapetus I", startYear: "0535", endYear: "0536", description: "Birth name: Agapetus. He persuaded Emperor Justinian I to depose the Monophysite Patriarch Anthimus of Constantinople. He died in Constantinople before returning to Rome." },
  { name: "St. Silverius", startYear: "0536", endYear: "0537", description: "Birth name: Silverius. Son of Pope St. Hormisdas, he was forcibly deposed by the Byzantine general Belisarius and exiled to the island of Ponza, where he died." },
  { name: "Vigilius", startYear: "0537", endYear: "0555", description: "Birth name: Vigilius. His controversial pontificate was dominated by the Three Chapters Controversy, and he was physically abducted to Constantinople by Emperor Justinian I." },
  { name: "Pelagius I", startYear: "0556", endYear: "0561", description: "Birth name: Pelagius. Appointed with the backing of Emperor Justinian I, he worked to rebuild Rome after the devastation of the Gothic Wars." },
  { name: "John III", startYear: "0561", endYear: "0574", description: "Birth name: Catelinus. He governed during the Lombard invasion of Italy, devastating much of the peninsula." },
  { name: "Benedict I", startYear: "0575", endYear: "0579", description: "Birth name: Boniface. His pontificate was overshadowed by the Lombard invasion and a devastating famine and plague." },
  { name: "Pelagius II", startYear: "0579", endYear: "0590", description: "Birth name: Pelagius. He was consecrated without imperial confirmation, a significant step in papal independence. He dispatched the future Pope Gregory the Great as ambassador to Constantinople." },
  // 6th-10th century
  { name: "St. Gregory I (the Great)", startYear: "0590", endYear: "0604", description: "Birth name: Gregory. One of the most influential popes in history, he reformed the liturgy (Gregorian chant bears his name), sent missionaries to evangelize England, and laid the groundwork for medieval papal authority." },
  { name: "Sabinian", startYear: "0604", endYear: "0606", description: "Birth name: Sabinianus. He reversed several of Gregory the Great's policies, notably distributing grain for profit rather than freely." },
  { name: "Boniface III", startYear: "0607", endYear: "0607", description: "Birth name: Bonifacius. His brief papacy obtained a decree from Emperor Phocas confirming Rome as the head of all churches." },
  { name: "St. Boniface IV", startYear: "0608", endYear: "0615", description: "Birth name: Bonifacius. He converted the Roman Pantheon into a Christian church dedicated to the Virgin Mary and all martyrs." },
  { name: "St. Adeodatus I", startYear: "0615", endYear: "0618", description: "Birth name: Deusdedit. The first pope to use lead seals (bullae) on papal documents, he was known for his care of the Roman clergy." },
  { name: "Boniface V", startYear: "0619", endYear: "0625", description: "Birth name: Bonifacius. He advanced the Christianization of England and worked to establish the right of sanctuary in churches." },
  { name: "Honorius I", startYear: "0625", endYear: "0638", description: "Birth name: Honorius. He was posthumously condemned by the Third Council of Constantinople (681) for supporting the Monothelite heresy." },
  { name: "Severinus", startYear: "0640", endYear: "0640", description: "Birth name: Severinus. His papacy lasted only two months, preceded by nearly two years of delay as imperial officials plundered the Lateran Palace." },
  { name: "John IV", startYear: "0640", endYear: "0642", description: "Birth name: Ioannes. A Dalmatian by birth, he defended the orthodoxy of Pope Honorius I and ransomed captives taken by Slavic and Avar invaders." },
  { name: "Theodore I", startYear: "0642", endYear: "0649", description: "Birth name: Theodoros. A Greek from Jerusalem, he vigorously opposed the Monothelite heresy and excommunicated the Patriarch of Constantinople." },
  { name: "St. Martin I", startYear: "0649", endYear: "0655", description: "Birth name: Martinus. He convened the Lateran Council of 649, which condemned Monothelitism. Emperor Constans II had him arrested and exiled to Crimea, where he died from mistreatment." },
  { name: "St. Eugene I", startYear: "0654", endYear: "0657", description: "Birth name: Eugenius. Elected while Martin I was still alive in exile, he continued resistance to Monothelitism." },
  { name: "St. Vitalian", startYear: "0657", endYear: "0672", description: "Birth name: Vitalianus. He worked to restore relations between Rome and the Byzantine Empire and appointed Theodore of Tarsus as Archbishop of Canterbury." },
  { name: "Adeodatus II", startYear: "0672", endYear: "0676", description: "Birth name: Adeodatus. A Roman Benedictine monk known for his personal piety and generosity." },
  { name: "Donus", startYear: "0676", endYear: "0678", description: "Birth name: Donus. He restored several Roman churches and settled a schism with the archbishop of Ravenna." },
  { name: "St. Agatho", startYear: "0678", endYear: "0681", description: "Birth name: Agatho. The Third Council of Constantinople (680-681), supported by his legates, formally condemned Monothelitism and vindicated the Roman position on the two wills of Christ." },
  { name: "St. Leo II", startYear: "0682", endYear: "0683", description: "Birth name: Leo. He confirmed the decrees of the Third Council of Constantinople and approved the posthumous condemnation of Honorius I for negligence." },
  { name: "St. Benedict II", startYear: "0684", endYear: "0685", description: "Birth name: Benedictus. He petitioned Emperor Constantine IV to allow papal consecration without waiting for imperial confirmation." },
  { name: "John V", startYear: "0685", endYear: "0686", description: "Birth name: Ioannes. A Syrian by origin, he attended the Third Council of Constantinople as a papal representative before his election." },
  { name: "Conon", startYear: "0686", endYear: "0687", description: "Birth name: Conon. Elected as a compromise candidate between rival clerical factions." },
  { name: "Theodore", startYear: "0687", endYear: "0687", isAntiPope: true, description: "Birth name: Theodorus. Elected by a rival faction simultaneously with Paschal; both were set aside when Sergius I was chosen as legitimate pope." },
  { name: "Paschal", startYear: "0687", endYear: "0692", isAntiPope: true, description: "Birth name: Paschalis. He bribed Byzantine officials to secure election against Sergius I, and continued to intrigue until he was condemned and imprisoned." },
  { name: "St. Sergius I", startYear: "0687", endYear: "0701", description: "Birth name: Sergius. A Syrian-born pope who resisted the Quinisext Council's canons and introduced the Agnus Dei into the Latin Mass." },
  { name: "John VI", startYear: "0701", endYear: "0705", description: "Birth name: Ioannes. A Greek by birth, he successfully pacified the violent exarch Theophylact by personally interceding with his troops." },
  { name: "John VII", startYear: "0705", endYear: "0707", description: "Birth name: Ioannes. The son of a Byzantine official, he was a notable patron of the arts who commissioned important mosaics in Rome." },
  { name: "Sisinnius", startYear: "0708", endYear: "0708", description: "Birth name: Sisinnius. His papacy lasted only twenty days, one of the shortest in history." },
  { name: "Constantine", startYear: "0708", endYear: "0715", description: "Birth name: Constantinus. The last pope to visit Constantinople for over 1,200 years, he negotiated with Emperor Justinian II." },
  { name: "St. Gregory II", startYear: "0715", endYear: "0731", description: "Birth name: Gregorius. He opposed Emperor Leo III's iconoclast edicts and oversaw the missionary work of St. Boniface in Germany." },
  { name: "St. Gregory III", startYear: "0731", endYear: "0741", description: "Birth name: Gregorius. The last pope to seek confirmation from a Byzantine emperor, he convened a synod condemning iconoclasm." },
  { name: "St. Zachary", startYear: "0741", endYear: "0752", description: "Birth name: Zacharias. The last Greek-born pope for over a millennium, he sanctioned the deposition of the last Merovingian king, paving the way for Carolingian rule." },
  { name: "Stephen II", startYear: "0752", endYear: "0757", description: "Birth name: Stephanus. He forged the pivotal Frankish-papal alliance by anointing Pepin III as king, who then donated conquered territories to the papacy - the origin of the Papal States." },
  { name: "St. Paul I", startYear: "0757", endYear: "0767", description: "Birth name: Paulus. The brother of his predecessor Stephen II, he maintained the Frankish alliance and continued defending Church interests against Lombard pressure." },
  { name: "Constantine II", startYear: "0767", endYear: "0768", isAntiPope: true, description: "Birth name: Constantinus. A layman forcibly ordained and imposed on Rome by his brother, the Lombard duke Toto of Nepi; he was deposed and condemned." },
  { name: "Philip", startYear: "0768", endYear: "0768", isAntiPope: true, description: "Birth name: Philippus. Installed by the Lombard king Desiderius, his reign lasted only a single day before he voluntarily withdrew." },
  { name: "Stephen III", startYear: "0768", endYear: "0772", description: "Birth name: Stephanus. He convened the Lateran Council of 769, which decreed that only cardinal clergy could be elected pope." },
  { name: "Adrian I", startYear: "0772", endYear: "0795", description: "Birth name: Hadrianus. His long pontificate saw him forge a close alliance with Charlemagne and play a key role in the Second Council of Nicaea (787), restoring the veneration of icons." },
  { name: "St. Leo III", startYear: "0795", endYear: "0816", description: "Birth name: Leo. He crowned Charlemagne as Emperor of the Romans on Christmas Day 800, creating the template for the Holy Roman Empire." },
  // 9th-10th century
  { name: "Stephen IV", startYear: "0816", endYear: "0817", description: "Birth name: Stephen. He crowned Louis the Pious as Holy Roman Emperor in 816, cementing the alliance between the papacy and the Carolingian dynasty." },
  { name: "St. Paschal I", startYear: "0817", endYear: "0824", description: "Birth name: Paschal. He negotiated the Pactum Ludovicianum with Louis the Pious, defining the temporal boundaries of the Papal States." },
  { name: "Eugene II", startYear: "0824", endYear: "0827", description: "Birth name: Eugene. His pontificate saw the Constitutio Romana of 824, which placed the papacy under greater Frankish imperial oversight." },
  { name: "Valentine", startYear: "0827", endYear: "0827", description: "Birth name: Valentine. One of the shortest papacies in history, lasting only about 40 days." },
  { name: "Gregory IV", startYear: "0827", endYear: "0844", description: "Birth name: Gregory. He became entangled in the civil war among the sons of Louis the Pious. He promoted the feast of All Saints." },
  { name: "John", startYear: "0844", endYear: "0844", isAntiPope: true, description: "Birth name: John. Elected by a faction before the legitimate election process could be completed. He was quickly deposed and replaced by Sergius II." },
  { name: "Sergius II", startYear: "0844", endYear: "0847", description: "Birth name: Sergius. His pontificate was marked by the devastating Arab sack of Rome in 846, during which St. Peter's Basilica was plundered." },
  { name: "St. Leo IV", startYear: "0847", endYear: "0855", description: "Birth name: Leo. He oversaw the construction of the Leonine Wall around the Vatican to protect it from further Arab raids." },
  { name: "Benedict III", startYear: "0855", endYear: "0858", description: "Birth name: Benedict. His election was contested by the imperial faction who briefly installed Anastasius Bibliothecarius in his place." },
  { name: "Anastasius III Bibliothecarius", startYear: "0855", endYear: "0855", isAntiPope: true, description: "Birth name: Anastasius. A powerful cardinal and Vatican librarian forcibly installed by the imperial faction opposed to Benedict III's election." },
  { name: "St. Nicholas I (the Great)", startYear: "0858", endYear: "0867", description: "Birth name: Nicholas. One of the most assertive popes of the early medieval period, he vigorously defended papal supremacy over secular rulers and intervened in the Photian Schism." },
  { name: "Adrian II", startYear: "0867", endYear: "0872", description: "Birth name: Hadrian. He presided over the Fourth Council of Constantinople (869-870) and supported the missionary work of Saints Cyril and Methodius among the Slavs." },
  { name: "John VIII", startYear: "0872", endYear: "0882", description: "Birth name: John. He was the first pope to be assassinated, killed by members of his own entourage." },
  { name: "Marinus I", startYear: "0882", endYear: "0884", description: "Birth name: Marinus. He was the first pope elected who had previously served as a bishop, breaking a long-standing canonical tradition." },
  { name: "St. Adrian III", startYear: "0884", endYear: "0885", description: "Birth name: Hadrian. He died en route to the Diet of Worms and was later canonized." },
  { name: "Stephen V", startYear: "0885", endYear: "0891", description: "Birth name: Stephen. He faced considerable hardship from famine and continuing threats of Viking, Saracen, and Magyar raids across Europe." },
  { name: "Formosus", startYear: "0891", endYear: "0896", description: "Birth name: Formosus. His papacy was highly controversial, most infamously resulting in the macabre posthumous Cadaver Synod held by his successor Stephen VI." },
  { name: "Boniface VI", startYear: "0896", endYear: "0896", description: "Birth name: Boniface. His papacy lasted only about 15 days. He had previously been defrocked twice for immoral conduct." },
  { name: "Stephen VI", startYear: "0896", endYear: "0897", description: "Birth name: Stephen. He ordered the infamous Cadaver Synod, putting the exhumed corpse of Formosus on trial. He was subsequently deposed and strangled in prison." },
  { name: "Romanus", startYear: "0897", endYear: "0897", description: "Birth name: Romanus. His pontificate lasted only a few months. He annulled the decrees of the Cadaver Synod." },
  { name: "Theodore II", startYear: "0897", endYear: "0897", description: "Birth name: Theodore. His papacy lasted only about 20 days. He rehabilitated Formosus and ordered the respectful reburial of his remains." },
  { name: "John IX", startYear: "0898", endYear: "0900", description: "Birth name: John. He convened two synods that definitively rehabilitated Pope Formosus and invalidated the Cadaver Synod." },
  { name: "Benedict IV", startYear: "0900", endYear: "0903", description: "Birth name: Benedict. He was known for his generosity to the poor. He crowned Louis of Provence as Holy Roman Emperor in 901." },
  { name: "Leo V", startYear: "0903", endYear: "0903", description: "Birth name: Leo. He was deposed after only about 30 days in office by the priest Christopher, who usurped the papal throne." },
  { name: "Christopher", startYear: "0903", endYear: "0904", isAntiPope: true, description: "Birth name: Christopher. He overthrew and imprisoned the legitimate Pope Leo V to seize the papal throne. He was in turn deposed by Sergius III." },
  { name: "Sergius III", startYear: "0904", endYear: "0911", description: "Birth name: Sergius. He came to power with the support of the powerful Theophylact family, ushering in the period sometimes called the pornocracy." },
  { name: "Anastasius III", startYear: "0911", endYear: "0913", description: "Birth name: Anastasius. His brief pontificate was generally peaceful and he maintained good relations with Frankish and Italian rulers." },
  { name: "Lando", startYear: "0913", endYear: "0914", description: "Birth name: Lando. He is notable for being the last pope to take a name not previously used until John Paul I in 1978." },
  { name: "John X", startYear: "0914", endYear: "0928", description: "Birth name: John. He played a crucial military role in defeating the Saracens at the Battle of the Garigliano in 915. He was later deposed and smothered to death in prison." },
  { name: "Leo VI", startYear: "0928", endYear: "0928", description: "Birth name: Leo. His papacy lasted only about seven months. He was likely installed under the influence of the powerful Roman noblewoman Marozia." },
  { name: "Stephen VII", startYear: "0928", endYear: "0931", description: "Birth name: Stephen. He reigned under the control of Marozia, the dominant political force in Rome at the time." },
  { name: "John XI", startYear: "0931", endYear: "0935", description: "Birth name: John. Widely believed to be the illegitimate son of Marozia, he was reduced to a purely ceremonial role when she was overthrown by Alberic II." },
  { name: "Leo VII", startYear: "0936", endYear: "0939", description: "Birth name: Leo. He reigned under the control of Alberic II of Spoleto and was notable for his efforts at monastic reform with Abbot Odo of Cluny." },
  { name: "Stephen VIII", startYear: "0939", endYear: "0942", description: "Birth name: Stephen. He continued to reign under Alberic II's dominance and was reportedly disfigured after attempting to oppose Alberic's authority." },
  { name: "Marinus II", startYear: "0942", endYear: "0946", description: "Birth name: Marinus. He governed under the continued control of Alberic II and was known for his efforts in church reform." },
  { name: "Agapetus II", startYear: "0946", endYear: "0955", description: "Birth name: Agapetus. Another pope under Alberic II's dominance, he promoted church reform and supported the Cluniac movement." },
  { name: "John XII", startYear: "0955", endYear: "0964", description: "Birth name: Octavian. Son of Alberic II, he was only about 18 at his election and led a notoriously dissolute life. He crowned Otto I as Holy Roman Emperor in 962 but was later deposed for treachery." },
  { name: "Leo VIII", startYear: "0963", endYear: "0965", description: "Birth name: Leo. Installed by Emperor Otto I after John XII's deposition, his legitimacy was disputed since he was a layman ordained in a single day." },
  { name: "Benedict V", startYear: "0964", endYear: "0966", description: "Birth name: Benedict. Elected by the Romans against Emperor Otto I's wishes, he was deposed and exiled to Hamburg, where he died." },
  { name: "John XIII", startYear: "0965", endYear: "0972", description: "Birth name: John. Closely aligned with Emperor Otto I, he strengthened the partnership between the papacy and the Holy Roman Empire." },
  { name: "Benedict VI", startYear: "0973", endYear: "0974", description: "Birth name: Benedict. He was seized, imprisoned in Castel Sant'Angelo, and strangled by the faction of the antipope Boniface VII." },
  { name: "Boniface VII", startYear: "0974", endYear: "0974", isAntiPope: true, description: "Birth name: Franco. Installed by Roman nobles after orchestrating the murder of Pope Benedict VI. He was quickly driven out by imperial forces." },
  { name: "Benedict VII", startYear: "0974", endYear: "0983", description: "Birth name: Benedict. Installed with imperial support, he had a relatively stable pontificate and worked actively to suppress simony." },
  { name: "John XIV", startYear: "0983", endYear: "0984", description: "Birth name: Pietro Canepanova. The returning antipope Boniface VII had him imprisoned in Castel Sant'Angelo, where he died." },
  { name: "John XV", startYear: "0985", endYear: "0996", description: "Birth name: John. He is notable for the first formal canonization of a saint by a pope, declaring Ulrich of Augsburg a saint in 993." },
  { name: "Gregory V", startYear: "0996", endYear: "0999", description: "Birth name: Bruno of Carinthia. The first German pope, appointed by his cousin Emperor Otto III at only about 24 years of age." },
  { name: "John XVI", startYear: "0997", endYear: "0998", isAntiPope: true, description: "Birth name: John Philagathos. A Greek-Italian bishop installed by the Roman noble Crescentius II. He was captured, brutally mutilated, and deposed." },
  // 11th century
  { name: "Sylvester II", startYear: "0999", endYear: "1003", description: "Birth name: Gerbert of Aurillac. The first French pope and a renowned scholar of mathematics, astronomy, and philosophy, he promoted the use of Arabic numerals in Europe." },
  { name: "John XVII", startYear: "1003", endYear: "1003", description: "Birth name: Siccone. He had one of the shortest pontificates on record, reigning for only about six months." },
  { name: "John XVIII", startYear: "1004", endYear: "1009", description: "Birth name: Fasanus. He presided over a period of relative stability under the influence of the powerful Crescentii family in Rome." },
  { name: "Sergius IV", startYear: "1009", endYear: "1012", description: "Birth name: Pietro Martino Buccaporci. He issued a bull calling for a crusade to recapture the Holy Sepulchre after its destruction by the Fatimid Caliph al-Hakim." },
  { name: "Benedict VIII", startYear: "1012", endYear: "1024", description: "Birth name: Theophylact of Tusculum. An energetic pope from the powerful Tusculani family, he allied with Emperor Henry II to combat simony and strengthen church discipline." },
  { name: "Gregory VI", startYear: "1012", endYear: "1012", isAntiPope: true, description: "Birth name: Unknown. An antipope set up by the rival Crescentii faction in opposition to Benedict VIII. He was quickly driven out." },
  { name: "John XIX", startYear: "1024", endYear: "1032", description: "Birth name: Romanus of Tusculum. Brother of Benedict VIII, he was a layman ordained and elevated to pope in a single day." },
  { name: "Benedict IX (1st)", startYear: "1032", endYear: "1044", description: "Birth name: Theophylact of Tusculum. Elected pope as a young man through family influence, his pontificate was scandalous and turbulent. He is one of the few men to hold the papacy on three separate occasions." },
  { name: "Sylvester III", startYear: "1045", endYear: "1045", isAntiPope: true, description: "Birth name: Giovanni dei Crescenzi. Elected while Benedict IX was still living. His claim was declared invalid and he was deposed after about six weeks." },
  { name: "Benedict IX (2nd)", startYear: "1045", endYear: "1045", description: "Birth name: Theophylact of Tusculum. He briefly reclaimed the papacy in April 1045, only to abdicate a few months later in exchange for a sum of money." },
  { name: "Gregory VI", startYear: "1045", endYear: "1046", description: "Birth name: Johannes Gratianus. He became pope after purchasing the office from Benedict IX, genuinely intending reform. He was deposed at the Synod of Sutri in 1046 for simony." },
  { name: "Clement II", startYear: "1046", endYear: "1047", description: "Birth name: Suidger of Morsleben. Appointed by Emperor Henry III after the Synod of Sutri, he was the first of a series of German reform popes." },
  { name: "Benedict IX (3rd)", startYear: "1047", endYear: "1048", description: "Birth name: Theophylact of Tusculum. He seized the papacy for a third time after Clement II's death and is regarded as one of the most controversial figures in papal history." },
  { name: "Damasus II", startYear: "1048", endYear: "1048", description: "Birth name: Poppo of Brixen. Appointed by Emperor Henry III, his pontificate lasted a mere 23 days before he died." },
  { name: "St. Leo IX", startYear: "1049", endYear: "1054", description: "Birth name: Bruno of Egisheim-Dagsburg. A pivotal reforming pope who energized the Gregorian Reform movement. His papacy culminated in the Great Schism of 1054, which split Eastern and Western Christianity." },
  { name: "Victor II", startYear: "1055", endYear: "1057", description: "Birth name: Gebhard of Dollnstein-Hirschberg. A close associate of Emperor Henry III, he was the last pope to be chosen by an emperor." },
  { name: "Stephen IX", startYear: "1057", endYear: "1058", description: "Birth name: Frederick of Lorraine. A committed church reformer, he was elected without imperial consultation, marking a shift toward greater papal independence." },
  { name: "Benedict X", startYear: "1058", endYear: "1059", isAntiPope: true, description: "Birth name: Giovanni Mincio. Elected by a Roman faction in violation of new electoral procedures. The reformers declared his election invalid." },
  { name: "Nicholas II", startYear: "1059", endYear: "1061", description: "Birth name: Gerard de Bourgogne. He issued the landmark decree In Nomine Domini (1059), placing the election of popes exclusively in the hands of the College of Cardinals." },
  { name: "Alexander II", startYear: "1061", endYear: "1073", description: "Birth name: Anselmo da Baggio. The first pope elected solely by the College of Cardinals under the new 1059 rules. He gave papal blessing to William the Conqueror's invasion of England." },
  { name: "Honorius II", startYear: "1061", endYear: "1064", isAntiPope: true, description: "Birth name: Cadalus of Parma. Elected by a German synod under imperial influence in opposition to Alexander II. He never gained general recognition." },
  { name: "St. Gregory VII", startYear: "1073", endYear: "1085", description: "Birth name: Hildebrand of Sovana. One of the most influential popes of the Middle Ages, he launched the Gregorian Reform and his conflict with Emperor Henry IV led to the famous penance at Canossa (1077)." },
  { name: "Clement III", startYear: "1080", endYear: "1100", isAntiPope: true, description: "Birth name: Guibert of Ravenna. Set up by Emperor Henry IV as antipope against Gregory VII, he had the longest reign of any antipope." },
  { name: "Bl. Victor III", startYear: "1086", endYear: "1087", description: "Birth name: Dauferio (Desiderius) of Benevento. Abbot of Monte Cassino, he reluctantly accepted election and reigned for less than a year." },
  { name: "Bl. Urban II", startYear: "1088", endYear: "1099", description: "Birth name: Odo of Chatillon. Best known for calling the First Crusade at the Council of Clermont in 1095. He died just two weeks before the Crusaders captured Jerusalem." },
  { name: "Paschal II", startYear: "1099", endYear: "1118", description: "Birth name: Raniero da Blera. His long pontificate was dominated by the Investiture Controversy. He was captured and imprisoned by Emperor Henry V." },
  { name: "Theodoric", startYear: "1100", endYear: "1102", isAntiPope: true, description: "Birth name: Unknown. Elevated as antipope by supporters of the deceased Clement III. He was captured and confined to a monastery." },
  { name: "Albert", startYear: "1102", endYear: "1102", isAntiPope: true, description: "Birth name: Unknown. Briefly set up as antipope by remaining partisans of the Clementine schism. His claim lasted only weeks before he was arrested." },
  { name: "Sylvester IV", startYear: "1105", endYear: "1111", isAntiPope: true, description: "Birth name: Maginulf. Elected antipope by Roman nobles and supporters of Emperor Henry V in opposition to Paschal II." },
  // 12th century
  { name: "Gelasius II", startYear: "1118", endYear: "1119", description: "Birth name: Giovanni di Gaeta. Elected amid violent opposition, he was physically attacked and briefly imprisoned before fleeing to France, where he died in exile at Cluny." },
  { name: "Gregory VIII", startYear: "1118", endYear: "1121", isAntiPope: true, description: "Birth name: Maurice Bourdin. Set up as antipope by Emperor Henry V during the Investiture Controversy; he was captured by Callixtus II in 1121." },
  { name: "Callixtus II", startYear: "1119", endYear: "1124", description: "Birth name: Guy of Burgundy. He brought the Investiture Controversy to an end by negotiating the Concordat of Worms (1122) with Emperor Henry V." },
  { name: "Honorius II", startYear: "1124", endYear: "1130", description: "Birth name: Lamberto Scannabecchi. His election was initially disputed but he consolidated papal influence by recognizing Lothair III as Holy Roman Emperor." },
  { name: "Celestine II", startYear: "1124", endYear: "1124", isAntiPope: true, description: "Birth name: Teobaldo Buccapecco. Elected by a minority faction immediately after Honorius II was chosen, he quickly yielded." },
  { name: "Innocent II", startYear: "1130", endYear: "1143", description: "Birth name: Gregorio Papareschi. His election triggered an eight-year schism with Antipope Anacletus II; with the support of St. Bernard of Clairvaux he ultimately prevailed, and the Second Lateran Council (1139) reunified the Church." },
  { name: "Anacletus II", startYear: "1130", endYear: "1138", isAntiPope: true, description: "Birth name: Pietro Pierleoni. Elected the same day as Innocent II by a rival faction, he held Rome for most of the schism but died before it was resolved." },
  { name: "Victor IV", startYear: "1138", endYear: "1138", isAntiPope: true, description: "Birth name: Gregorio Conti. Elected by remaining supporters of Anacletus II, he submitted to Pope Innocent II within a few months." },
  { name: "Celestine II", startYear: "1143", endYear: "1144", description: "Birth name: Guido di Castello. A former student of Peter Abelard, his brief pontificate lifted the interdict on France imposed by his predecessor." },
  { name: "Lucius II", startYear: "1144", endYear: "1145", description: "Birth name: Gherardo Caccianemici dal Orso. He died from a head wound sustained during an attempt to retake the Capitol from the Roman commune." },
  { name: "Bl. Eugene III", startYear: "1145", endYear: "1153", description: "Birth name: Bernardo Pignatelli. A Cistercian monk and disciple of St. Bernard of Clairvaux, he was the first Cistercian pope and launched the Second Crusade." },
  { name: "Anastasius IV", startYear: "1153", endYear: "1154", description: "Birth name: Corrado della Suburra. His brief pontificate was notably peaceful; he worked to reconcile the papacy with the Holy Roman Empire." },
  { name: "Adrian IV", startYear: "1154", endYear: "1159", description: "Birth name: Nicholas Breakspear. The only Englishman ever to become pope, he granted Henry II lordship over Ireland and had Arnold of Brescia executed." },
  { name: "Alexander III", startYear: "1159", endYear: "1181", description: "Birth name: Rolando Bandinelli. He endured an eighteen-year schism backed by Emperor Frederick Barbarossa, ultimately triumphing at the Peace of Venice (1177) and presiding over the Third Lateran Council (1179)." },
  { name: "Victor IV", startYear: "1159", endYear: "1164", isAntiPope: true, description: "Birth name: Ottavio di Montecelio. Installed by Frederick Barbarossa in opposition to Alexander III, he was the first of four imperial antipopes." },
  { name: "Paschal III", startYear: "1164", endYear: "1168", isAntiPope: true, description: "Birth name: Guido of Crema. Appointed by Frederick Barbarossa, he controversially canonized Charlemagne in 1165, an act never recognized by the Church." },
  { name: "Callixtus III", startYear: "1168", endYear: "1178", isAntiPope: true, description: "Birth name: Giovanni of Struma. The third antipope set up by Frederick Barbarossa, he submitted to Alexander III after the Peace of Venice (1177)." },
  { name: "Innocent III", startYear: "1179", endYear: "1180", isAntiPope: true, description: "Birth name: Lando of Sezze. The fourth and last antipope of the Alexandrine schism, a minor claimant captured and imprisoned in a monastery." },
  { name: "Lucius III", startYear: "1181", endYear: "1185", description: "Birth name: Ubaldo Allucingoli. He collaborated with Emperor Frederick Barbarossa to issue Ad abolendam (1184), one of the earliest frameworks for systematic prosecution of heresy." },
  { name: "Urban III", startYear: "1185", endYear: "1187", description: "Birth name: Uberto Crivelli. His pontificate was consumed by conflict with Frederick Barbarossa. He died shortly after learning of Saladin's victory at the Battle of Hattin." },
  { name: "Gregory VIII", startYear: "1187", endYear: "1187", description: "Birth name: Alberto de Morra. Though his pontificate lasted only 57 days, he issued Audita tremendi, calling for the Third Crusade after the fall of Jerusalem." },
  { name: "Clement III", startYear: "1187", endYear: "1191", description: "Birth name: Paolo Scolari. He reconciled the papacy with the Roman commune and organized the departure of the Third Crusade." },
  { name: "Celestine III", startYear: "1191", endYear: "1198", description: "Birth name: Giacinto Bobone. Elected at approximately 85 years of age, he crowned Henry VI as Holy Roman Emperor." },
  { name: "Innocent III", startYear: "1198", endYear: "1216", description: "Birth name: Lotario dei Conti di Segni. One of the most powerful popes in history, he asserted sweeping papal supremacy, launched the Fourth Crusade and the Albigensian Crusade, and convened the Fourth Lateran Council (1215)." },

  // 13th century
  { name: "Honorius III", startYear: "1216", endYear: "1227", description: "Birth name: Cencio Savelli. He approved the Dominican and Franciscan orders and pressed Emperor Frederick II to lead the Fifth Crusade." },
  { name: "Gregory IX", startYear: "1227", endYear: "1241", description: "Birth name: Ugolino di Conti. A close friend of St. Francis of Assisi, he canonized both Francis and Dominic, commissioned the Decretales, and formally established the papal Inquisition." },
  { name: "Celestine IV", startYear: "1241", endYear: "1241", description: "Birth name: Goffredo Castiglioni. He died just seventeen days after his election, before he could even be consecrated." },
  { name: "Innocent IV", startYear: "1243", endYear: "1254", description: "Birth name: Sinibaldo Fieschi. A formidable canon lawyer, he deposed Emperor Frederick II at the First Council of Lyon (1245) and sent the first diplomatic missions to the Mongol court." },
  { name: "Alexander IV", startYear: "1254", endYear: "1261", description: "Birth name: Rinaldo di Jenne. A nephew of Gregory IX, his pontificate was marked by conflict with Manfred of Sicily and strong support for the mendicant orders." },
  { name: "Urban IV", startYear: "1261", endYear: "1264", description: "Birth name: Jacques Pantaleon. The first pope elected without being a cardinal, he commissioned Thomas Aquinas to compose the liturgy for the feast of Corpus Christi." },
  { name: "Clement IV", startYear: "1265", endYear: "1268", description: "Birth name: Guy Foulques. A former French lawyer and widower, he supported Charles of Anjou's conquest of Sicily and was patron to the scientist Roger Bacon." },
  { name: "Bl. Gregory X", startYear: "1271", endYear: "1276", description: "Birth name: Teobaldo Visconti. Elected after a nearly three-year vacancy, he convened the Second Council of Lyon (1274), achieving a short-lived union with the Eastern Church." },
  { name: "Bl. Innocent V", startYear: "1276", endYear: "1276", description: "Birth name: Pierre de Tarentaise. The first Dominican pope, he reigned for only five months. A distinguished theologian and former colleague of Thomas Aquinas." },
  { name: "Adrian V", startYear: "1276", endYear: "1276", description: "Birth name: Ottobono Fieschi. He reigned for only about five weeks and died before being ordained a priest or consecrated a bishop." },
  { name: "John XXI", startYear: "1276", endYear: "1277", description: "Birth name: Pedro Juliao (Petrus Hispanus). The only Portuguese pope and a celebrated physician and philosopher. He died when the ceiling of his study collapsed on him." },
  { name: "Nicholas III", startYear: "1277", endYear: "1280", description: "Birth name: Giovanni Gaetano Orsini. He secured the Papal States territorially and issued Exiit qui seminat defining Franciscan poverty. Dante placed him in Hell for nepotism." },
  { name: "Martin IV", startYear: "1281", endYear: "1285", description: "Birth name: Simon de Brion. A Frenchman closely aligned with Charles of Anjou, his pontificate was overshadowed by the Sicilian Vespers revolt (1282)." },
  { name: "Honorius IV", startYear: "1285", endYear: "1287", description: "Birth name: Giacomo Savelli. So crippled by gout he could barely move, yet he governed effectively, promoted Oriental language studies, and continued to support the mendicant orders." },
  { name: "Nicholas IV", startYear: "1288", endYear: "1292", description: "Birth name: Girolamo Masci. The first Franciscan pope, he sent missionaries to China and witnessed the fall of the last Crusader strongholds in the Holy Land." },
  { name: "St. Celestine V", startYear: "1294", endYear: "1294", description: "Birth name: Pietro Angelerio (Pietro da Morrone). An elderly hermit-monk who established a pope's right to abdicate and then exercised that right after only five months, the only pope to freely resign before Benedict XVI." },
  { name: "Boniface VIII", startYear: "1294", endYear: "1303", description: "Birth name: Benedetto Caetani. He made sweeping claims of papal supremacy in Unam Sanctam (1302), bringing him into direct conflict with Philip IV of France, who had him arrested at Anagni." },
  // 14th century - Avignon Papacy & Western Schism
  { name: "Bl. Benedict XI", startYear: "1303", endYear: "1304", description: "Birth name: Niccolo Boccasini. A Dominican friar, he served a brief pontificate focused on reconciling the papacy with France after the conflict between Boniface VIII and Philip IV." },
  { name: "Clement V", startYear: "1305", endYear: "1314", description: "Birth name: Bertrand de Got. He transferred the papal seat to Avignon in 1309, beginning the Avignon Papacy, and under pressure from Philip IV suppressed the Knights Templar." },
  { name: "John XXII", startYear: "1316", endYear: "1334", description: "Birth name: Jacques Duese. The second Avignon pope, he centralized church administration and sparked controversy with his views on the beatific vision, which he later recanted." },
  { name: "Nicholas V", startYear: "1328", endYear: "1330", isAntiPope: true, description: "Birth name: Pietro Rainalducci. Set up as antipope by Emperor Louis IV of Bavaria in opposition to John XXII. He submitted in 1330 and spent his remaining years in captivity." },
  { name: "Benedict XII", startYear: "1334", endYear: "1342", description: "Birth name: Jacques Fournier. A former inquisitor and Cistercian monk, he attempted to reform monastic orders and definitively settled the beatific vision controversy with Benedictus Deus." },
  { name: "Clement VI", startYear: "1342", endYear: "1352", description: "Birth name: Pierre Roger. A lavish patron of the arts, he purchased Avignon outright and provided refuge to Jews being scapegoated during the Black Death." },
  { name: "Innocent VI", startYear: "1352", endYear: "1362", description: "Birth name: Etienne Aubert. He undertook meaningful reforms of the papal curia and relied on Cardinal Albornoz to reassert papal authority over the Papal States in Italy." },
  { name: "Bl. Urban V", startYear: "1362", endYear: "1370", description: "Birth name: Guillaume de Grimoard. A Benedictine monk who maintained his monastic discipline, he temporarily returned the papacy to Rome in 1367 before being forced back to Avignon." },
  { name: "Gregory XI", startYear: "1370", endYear: "1378", description: "Birth name: Pierre Roger de Beaufort. Influenced by St. Catherine of Siena, he permanently returned the papacy from Avignon to Rome in 1377, ending the nearly seven-decade Avignon Papacy." },

  // Western Schism period
  { name: "Urban VI", startYear: "1378", endYear: "1389", description: "Birth name: Bartolomeo Prignano. His erratic conduct led cardinals to declare his election invalid and elect an antipope, directly triggering the Western Schism." },
  { name: "Clement VII", startYear: "1378", endYear: "1394", isAntiPope: true, description: "Birth name: Robert of Geneva. Elected by cardinals who repudiated Urban VI, he reestablished the rival Avignon obedience, inaugurating the Western Schism." },
  { name: "Boniface IX", startYear: "1389", endYear: "1404", description: "Birth name: Pietro Tomacelli. He consolidated the Roman obedience during the Western Schism and was known for extensive use of indulgences to fund campaigns." },
  { name: "Benedict XIII", startYear: "1394", endYear: "1423", isAntiPope: true, description: "Birth name: Pedro de Luna. The Avignon claimant who stubbornly refused to abdicate despite being abandoned by nearly all supporters and deposed by multiple councils." },
  { name: "Innocent VII", startYear: "1404", endYear: "1406", description: "Birth name: Cosimo Gentile de' Migliorati. He reigned briefly during the Western Schism as the Roman claimant, troubled by violent unrest in Rome." },
  { name: "Gregory XII", startYear: "1406", endYear: "1415", description: "Birth name: Angelo Correr. The last Roman claimant of the Western Schism, he made the extraordinary act of resignation at the Council of Constance in 1415 to heal the schism." },
  { name: "Alexander V", startYear: "1409", endYear: "1410", isAntiPope: true, description: "Birth name: Petros Philargos. Elected by the Council of Pisa, he is regarded as an antipope since his election created a third obedience rather than resolving the crisis." },
  { name: "John XXIII", startYear: "1410", endYear: "1415", isAntiPope: true, description: "Birth name: Baldassare Cossa. Successor to the Pisan claimant, he convoked the Council of Constance but fled when the council moved to try him; he was deposed for heresy, simony, and immorality." },

  // Post-Schism
  { name: "Martin V", startYear: "1417", endYear: "1431", description: "Birth name: Oddone Colonna. Elected by the Council of Constance, he definitively ended the Western Schism and restored unified papal authority." },
  { name: "Clement VIII", startYear: "1423", endYear: "1429", isAntiPope: true, description: "Birth name: Gil Sanchez Munoz. Elected by the tiny remaining faction loyal to Benedict XIII, he abdicated in 1429, ending the last remnant of the Western Schism." },
  { name: "Benedict XIV", startYear: "1425", endYear: "1430", isAntiPope: true, description: "Birth name: Bernard Garnier (disputed). A shadowy figure elected by a tiny rump faction, he had virtually no support and his claim was abandoned when Clement VIII abdicated." },
  { name: "Eugene IV", startYear: "1431", endYear: "1447", description: "Birth name: Gabriele Condulmer. His pontificate was dominated by conflict with the conciliarist movement at the Council of Basel and his sponsorship of the Council of Florence seeking reunion with the Eastern Church." },
  { name: "Felix V", startYear: "1439", endYear: "1449", isAntiPope: true, description: "Birth name: Amadeus VIII, Duke of Savoy. The last antipope in Church history, he abdicated in 1449 and submitted to Nicholas V." },
  { name: "Nicholas V", startYear: "1447", endYear: "1455", description: "Birth name: Tommaso Parentucelli. A renowned humanist scholar, he founded the Vatican Library and is considered the first Renaissance pope." },
  // 15th-16th century (Renaissance)
  { name: "Callixtus III", startYear: "1455", endYear: "1458", description: "Birth name: Alfonso de Borja. The first Borgia pope, he dedicated his papacy to organizing a crusade against the Ottomans and posthumously annulled Joan of Arc's conviction." },
  { name: "Pius II", startYear: "1458", endYear: "1464", description: "Birth name: Enea Silvio Piccolomini. A renowned Renaissance humanist and writer, he condemned appeals to councils over papal authority with Execrabilis and futilely attempted to launch a crusade." },
  { name: "Paul II", startYear: "1464", endYear: "1471", description: "Birth name: Pietro Barbo. He clashed with the College of Cardinals and humanist scholars, and is remembered for his love of luxury and collecting antiquities." },
  { name: "Sixtus IV", startYear: "1471", endYear: "1484", description: "Birth name: Francesco della Rovere. A Franciscan theologian and major patron of the arts, he built the Sistine Chapel but was also involved in the Pazzi Conspiracy against the Medici." },
  { name: "Innocent VIII", startYear: "1484", endYear: "1492", description: "Birth name: Giovanni Battista Cybo. He issued the bull Summis desiderantes affectibus (1484), which intensified the persecution of witchcraft in Europe." },
  { name: "Alexander VI", startYear: "1492", endYear: "1503", description: "Birth name: Rodrigo de Borja (Borgia). One of the most controversial popes in history, he openly acknowledged his children including Cesare and Lucrezia Borgia. He issued the Treaty of Tordesillas dividing the New World." },
  { name: "Pius III", startYear: "1503", endYear: "1503", description: "Birth name: Francesco Todeschini Piccolomini. Nephew of Pius II, his papacy lasted only 26 days before his death from illness." },
  { name: "Julius II", startYear: "1503", endYear: "1513", description: "Birth name: Giuliano della Rovere. Known as the 'Warrior Pope,' he commissioned Michelangelo to paint the Sistine Chapel ceiling and laid the foundation stone of the new St. Peter's Basilica." },
  { name: "Leo X", startYear: "1513", endYear: "1521", description: "Birth name: Giovanni di Lorenzo de' Medici. Son of Lorenzo the Magnificent, his sale of indulgences to fund St. Peter's directly provoked Martin Luther's Ninety-Five Theses and the Protestant Reformation." },
  { name: "Adrian VI", startYear: "1522", endYear: "1523", description: "Birth name: Adriaan Florenszoon Boeyens. The last non-Italian pope before John Paul II, this austere Dutch theologian attempted genuine reform but met fierce resistance." },
  { name: "Clement VII", startYear: "1523", endYear: "1534", description: "Birth name: Giulio di Giuliano de' Medici. His indecisive policy contributed to the Sack of Rome in 1527, and his refusal to annul Henry VIII's marriage triggered the English Reformation." },
  { name: "Paul III", startYear: "1534", endYear: "1549", description: "Birth name: Alessandro Farnese. A pivotal figure of the Counter-Reformation, he convened the Council of Trent (1545), approved the Jesuit order, and issued Sublimus Dei affirming indigenous peoples' rights." },
  { name: "Julius III", startYear: "1550", endYear: "1555", description: "Birth name: Giovanni Maria Ciocchi del Monte. He reconvened the Council of Trent and worked to restore Catholicism in England under Queen Mary I." },
  { name: "Marcellus II", startYear: "1555", endYear: "1555", description: "Birth name: Marcello Cervini degli Spannochi. A reform-minded cardinal who retained his baptismal name upon election, he died after only 22 days as pope." },
  { name: "Paul IV", startYear: "1555", endYear: "1559", description: "Birth name: Gian Pietro Carafa. A zealous reformer who co-founded the Theatine order, expanded the Roman Inquisition, instituted the Index of Forbidden Books, and enforced strict anti-Jewish policies." },
  { name: "Pius IV", startYear: "1559", endYear: "1565", description: "Birth name: Giovanni Angelo Medici. He successfully brought the Council of Trent to its conclusion in 1563, laying the doctrinal foundation for the Counter-Reformation." },
  { name: "St. Pius V", startYear: "1566", endYear: "1572", description: "Birth name: Antonio Ghislieri. A Dominican friar who rigorously implemented Trent's reforms, standardized the Tridentine Mass, and organized the Holy League whose victory at Lepanto (1571) halted Ottoman expansion." },
  { name: "Gregory XIII", startYear: "1572", endYear: "1585", description: "Birth name: Ugo Boncompagni. Best remembered for the 1582 Gregorian calendar reform that remains the standard civil calendar worldwide." },
  { name: "Sixtus V", startYear: "1585", endYear: "1590", description: "Birth name: Felice Peretti di Montalto. He restructured the Roman Curia, fixed the College of Cardinals at 70 members, and transformed Rome's urban landscape including completing St. Peter's dome." },
  { name: "Urban VII", startYear: "1590", endYear: "1590", description: "Birth name: Giovanni Battista Castagna. His papacy of only 13 days is the shortest in history. He is remembered for issuing the first known public smoking ban." },
  { name: "Gregory XIV", startYear: "1590", endYear: "1591", description: "Birth name: Niccolo Sfondrati. A sickly pope who aligned the papacy firmly with Spain and Philip II." },
  { name: "Innocent IX", startYear: "1591", endYear: "1591", description: "Birth name: Giovanni Antonio Facchinetti de Nuce. Elected at age 72 and in poor health, he died after only two months as pope." },
  // 17th century
  { name: "Clement VIII", startYear: "1592", endYear: "1605", description: "Birth name: Ippolito Aldobrandini. He absolved Henry IV of France from excommunication, bringing France back into the Church." },
  { name: "Leo XI", startYear: "1605", endYear: "1605", description: "Birth name: Alessandro Ottaviano de' Medici. He reigned for only 27 days, earning the nickname 'Papa Lampo' (Lightning Pope)." },
  { name: "Paul V", startYear: "1605", endYear: "1621", description: "Birth name: Camillo Borghese. He clashed with Venice in a major jurisdictional dispute and oversaw the condemnation of Galileo's Copernican views." },
  { name: "Gregory XV", startYear: "1621", endYear: "1623", description: "Birth name: Alessandro Ludovisi. He founded the Congregation for the Propagation of the Faith and canonized Ignatius of Loyola, Francis Xavier, and Teresa of Avila." },
  { name: "Urban VIII", startYear: "1623", endYear: "1644", description: "Birth name: Maffeo Vincenzo Barberini. He formally condemned Galileo Galilei in 1633 and was a significant patron of the arts, closely associated with Bernini and Roman Baroque culture." },
  { name: "Innocent X", startYear: "1644", endYear: "1655", description: "Birth name: Giovanni Battista Pamphilj. He condemned the Peace of Westphalia and opposed Jansenism with his bull Cum occasione." },
  { name: "Alexander VII", startYear: "1655", endYear: "1667", description: "Birth name: Fabio Chigi. He continued the struggle against Jansenism and oversaw the completion of Bernini's colonnade in St. Peter's Square." },
  { name: "Clement IX", startYear: "1667", endYear: "1669", description: "Birth name: Giulio Rospigliosi. His brief pontificate was marked by the fall of Crete to the Ottoman Turks despite his efforts to organize a Christian defense." },
  { name: "Clement X", startYear: "1670", endYear: "1676", description: "Birth name: Emilio Altieri. Elected at age 79, his reign saw continued conflicts with Louis XIV over Church appointments in France." },
  { name: "Bl. Innocent XI", startYear: "1676", endYear: "1689", description: "Birth name: Benedetto Odescalchi. A vigorous reformer who played a key role in organizing the coalition that defeated the Ottoman siege of Vienna in 1683. Beatified in 1956." },
  { name: "Alexander VIII", startYear: "1689", endYear: "1691", description: "Birth name: Pietro Vito Ottoboni. His short pontificate was marked by nepotism and continuing conflict with Louis XIV, though he condemned Jansenism and Quietism." },
  { name: "Innocent XII", startYear: "1691", endYear: "1700", description: "Birth name: Antonio Pignatelli. He issued the landmark bull formally prohibiting papal nepotism and resolved the long dispute with Louis XIV over Gallicanism." },

  // 18th century
  { name: "Clement XI", startYear: "1700", endYear: "1721", description: "Birth name: Giovanni Francesco Albani. He issued the bull Unigenitus (1713) condemning Jansenism, provoking fierce controversy in France for decades." },
  { name: "Innocent XIII", startYear: "1721", endYear: "1724", description: "Birth name: Michelangelo dei Conti. His brief pontificate continued efforts against Jansenism and saw tensions with the Jesuits over the Chinese Rites controversy." },
  { name: "Benedict XIII", startYear: "1724", endYear: "1730", description: "Birth name: Pietro Francesco Orsini. A Dominican friar and austere reformer, he was heavily manipulated by his corrupt secretary Cardinal Coscia." },
  { name: "Clement XII", startYear: "1730", endYear: "1740", description: "Birth name: Lorenzo Corsini. Elected at 79 and blind for much of his reign, he issued the first papal condemnation of Freemasonry in 1738." },
  { name: "Benedict XIV", startYear: "1740", endYear: "1758", description: "Birth name: Prospero Lorenzo Lambertini. Widely regarded as one of the most learned popes of the modern era, known for his wit, scholarship, and diplomatic skill." },
  { name: "Clement XIII", startYear: "1758", endYear: "1769", description: "Birth name: Carlo della Torre di Rezzonico. His pontificate was dominated by pressure from European monarchies to suppress the Jesuits, which he steadfastly refused." },
  { name: "Clement XIV", startYear: "1769", endYear: "1774", description: "Birth name: Giovanni Vincenzo Antonio Ganganelli. Bowing to pressure from France, Spain, and Portugal, he suppressed the Society of Jesus in 1773, one of the most controversial acts in modern papal history." },
  { name: "Pius VI", startYear: "1775", endYear: "1799", description: "Birth name: Giovanni Angelo Braschi. His pontificate ended in catastrophe as Napoleon's forces invaded the Papal States and he died in captivity in France." },
  // 19th century
  { name: "Pius VII", startYear: "1800", endYear: "1823", description: "Birth name: Barnaba Chiaramonti. He navigated the Napoleonic era, including his captivity by Napoleon, and negotiated the Concordat of 1801 restoring the Church in France." },
  { name: "Leo XII", startYear: "1823", endYear: "1829", description: "Birth name: Annibale Sermattei della Genga. A conservative reformer who worked to restore traditional Catholic discipline and strengthen the Papal States." },
  { name: "Pius VIII", startYear: "1829", endYear: "1830", description: "Birth name: Francesco Saverio Castiglioni. His brief pontificate focused on combating secret societies and religious indifferentism." },
  { name: "Gregory XVI", startYear: "1831", endYear: "1846", description: "Birth name: Bartolomeo Alberto Cappellari. He firmly opposed liberalism and nationalism in Mirari Vos and oversaw significant expansion of Catholic missions worldwide." },
  { name: "Bl. Pius IX", startYear: "1846", endYear: "1878", description: "Birth name: Giovanni Maria Mastai-Ferretti. The longest-reigning pope in history, he defined the dogma of the Immaculate Conception (1854) and convened Vatican I, which declared papal infallibility." },
  { name: "Leo XIII", startYear: "1878", endYear: "1903", description: "Birth name: Vincenzo Gioacchino Raffaele Luigi Pecci. He modernized Catholic social teaching with the landmark encyclical Rerum Novarum (1891), addressing workers' rights." },

  // 20th-21st century
  { name: "St. Pius X", startYear: "1903", endYear: "1914", description: "Birth name: Giuseppe Melchiorre Sarto. He condemned Modernism and promoted frequent Communion and the reform of Church music." },
  { name: "Benedict XV", startYear: "1914", endYear: "1922", description: "Birth name: Giacomo Paolo Giovanni Battista della Chiesa. He led the Church through World War I, advocating for peace and humanitarian relief, and issued the 1917 Code of Canon Law." },
  { name: "Pius XI", startYear: "1922", endYear: "1939", description: "Birth name: Ambrogio Damiano Achille Ratti. He established Vatican City through the Lateran Treaty of 1929 and condemned Nazism, Fascism, and Communism in separate encyclicals." },
  { name: "Pius XII", startYear: "1939", endYear: "1958", description: "Birth name: Eugenio Maria Giuseppe Giovanni Pacelli. He guided the Church through World War II and defined the dogma of the Assumption of Mary in 1950." },
  { name: "St. John XXIII", startYear: "1958", endYear: "1963", description: "Birth name: Angelo Giuseppe Roncalli. He shocked the world by convening the Second Vatican Council in 1962, launching the most sweeping renewal of the Catholic Church in centuries." },
  { name: "St. Paul VI", startYear: "1963", endYear: "1978", description: "Birth name: Giovanni Battista Enrico Antonio Maria Montini. He guided Vatican II to its conclusion and reaffirmed traditional teaching on contraception in Humanae Vitae (1968)." },
  { name: "John Paul I", startYear: "1978", endYear: "1978", description: "Birth name: Albino Luciani. Known as 'the Smiling Pope,' his pontificate lasted only 33 days before his sudden death." },
  { name: "St. John Paul II", startYear: "1978", endYear: "2005", description: "Birth name: Karol Jozef Wojtyla. The first non-Italian pope in over 450 years, he played a pivotal role in the fall of Communism and transformed the papacy through extensive world travels." },
  { name: "Benedict XVI", startYear: "2005", endYear: "2013", description: "Birth name: Joseph Aloisius Ratzinger. A noted theologian, he became the first pope to resign voluntarily since Gregory XII in 1415, citing declining health." },
  { name: "Francis", startYear: "2013", endYear: "2025", description: "Birth name: Jorge Mario Bergoglio. The first Jesuit pope and first from the Americas, he emphasized mercy, care for the poor, and environmental stewardship in Laudato Si'." },
  { name: "Leo XIV", startYear: "2025", endYear: "2026", description: "Birth name: Robert Francis Prevost. The first pope from the United States, elected in May 2025 after serving as Prefect of the Dicastery for Bishops." },
];
